arguments.file_text:
@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="d-flex list-unstyled justify-content-between p-0 m-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i;
            var status = GetStepStatus(step);
            <li class="step-item flex-fill text-center @status" role="listitem">
                @if (status == "completed")
                {
                    <button type="button" class="btn btn-link step-btn p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(step)">
                        <span class="step-circle">&#10003;</span>
                        <span class="step-label">@StepNames[step]</span>
                    </button>
                }
                else
                {
                    <span class="step-circle">@(step + 1)</span>
                    <span class="step-label">@StepNames[step]</span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly List<string> StepNames = new()
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepStatus(int step)
    {
