.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 2rem;
    height: 2rem;
    border-radius: 50%;
    font-weight: bold;
    font-size: 0.85rem;
    margin-bottom: 0.25rem;
}

.step-label {
    display: block;
    font-size: 0.8rem;
}

.step-item.active .step-circle {
    background-color: #0d6efd;
    color: white;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-circle {
    background-color: #198754;
    color: white;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.dimmed .step-circle {
    background-color: #dee2e6;
    color: #6c757d;
}

.step-item.dimmed .step-label {
    color: #adb5bd;
}

.step-btn {
    border: none;
    background: none;
    cursor: pointer;
}

.step-btn:hover .step-circle {
    opacity: 0.8;
}

