@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply
@using sv_4814acce08604935a05cd587ebe6908c.Models

<div class="card mb-3">
    <div class="card-body">
        @if (ShowRemove)
        {
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @Index</h6>
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            </div>
        }
        else
        {
            <h6 class="card-title mb-2">Position @Index</h6>
        }

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name</label>
                <input type="text" class="form-control" @bind="Entry.Company" @bind:event="oninput" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title</label>
                <input type="text" class="form-control" @bind="Entry.Title" @bind:event="oninput" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control" value="@FormatDate(Entry.StartDate)" @onchange="e => Entry.StartDate = ParseDate(e)" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@FormatDate(Entry.EndDate)" disabled="@Entry.IsCurrent"
                       @onchange="e => Entry.EndDate = ParseDate(e)" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check">
                    <input class="form-check-input" type="checkbox" id="current-@Index" @bind="Entry.IsCurrent"
                           @onclick="() => { if (!Entry.IsCurrent) Entry.EndDate = null; }" />
                    <label class="form-check-label" for="current-@Index">Currently employed here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @bind="Entry.Description" @bind:event="oninput"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; } = 1;
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private static string FormatDate(DateTime? date) => date?.ToString("yyyy-MM-dd") ?? "";

    private static DateTime? ParseDate(ChangeEventArgs e)
    {
        if (DateTime.TryParse(e.Value?.ToString(), out var d)) return d;
        return null;
    }
}

