@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply
@using sv_4814acce08604935a05cd587ebe6908c.Models

<h4 class="mb-3">Personal Information</h4>

<EditForm Model="Model" OnValidSubmit="HandleNext" FormName="personal-info-step">
    <DataAnnotationsValidator />

    @if (!string.IsNullOrEmpty(_emailError))
    {
        <div class="alert alert-danger">@_emailError</div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name</label>
            <InputText class="form-control" @bind-Value="Model.FullName" />
            <ValidationMessage For="() => Model.FullName" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address</label>
            <InputText class="form-control" @bind-Value="Model.Address" />
            <ValidationMessage For="() => Model.Address" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button type="submit" class="btn btn-primary" disabled="@_validating">
            @if (_validating)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Next
        </button>
    </div>
</EditForm>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private bool _validating;
    private string? _emailError;

    private async Task HandleNext()
    {
        _emailError = null;

        if (ValidateEmail is not null && !string.IsNullOrWhiteSpace(Model.Email))
        {
            _validating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Model.Email);
            _validating = false;

            if (!isValid)
            {
                _emailError = "This email address could not be verified. Please check it and try again.";
                return;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply
@using sv_4814acce08604935a05cd587ebe6908c.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryEditor Entry="Entries[index]"
                     Index="index + 1"
                     ShowRemove="Entries.Count > 1"
                     OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

@if (_hasValidationErrors)
{
    <div class="alert alert-danger">Please fill in the required fields (company, title, and start date) for each position.</div>
}

<div class="d-flex justify-content-between mt-4">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool _hasValidationErrors;

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _hasValidationErrors = Entries.Any(e =>
            string.IsNullOrWhiteSpace(e.Company) ||
            string.IsNullOrWhiteSpace(e.Title) ||
            e.StartDate is null);

        if (!_hasValidationErrors)
        {
            await OnNext.InvokeAsync();
        }
    }
}

@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply
@using sv_4814acce08604935a05cd587ebe6908c.Models

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceEditor Reference="References[index]"
                     Index="index + 1"
                     ShowRemove="References.Count > 2"
                     OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (_hasValidationErrors)
{
    <div class="alert alert-danger">Please fill in all required fields for each reference.</div>
}

<div class="d-flex justify-content-between mt-4">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool _hasValidationErrors;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        _hasValidationErrors = References.Any(r =>
            string.IsNullOrWhiteSpace(r.Name) ||
            string.IsNullOrWhiteSpace(r.Relationship) ||
            string.IsNullOrWhiteSpace(r.Email) ||
            string.IsNullOrWhiteSpace(r.Phone));

        if (!_hasValidationErrors)
        {
            await OnNext.InvokeAsync();
        }
    }
}

@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12"
              maxlength="@MaxLength"
              @bind="CoverLetter"
              @bind:event="oninput"
              @bind:after="NotifyChanged"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }
}

@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply
@using sv_4814acce08604935a05cd587ebe6908c.Models

<h4 class="mb-3">Review Your Application</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3">
                <h6>@entry.Title at @entry.Company</h6>
                <p class="text-muted mb-1">
                    @entry.StartDate?.ToString("MMM yyyy") &ndash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </p>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                <span class="text-muted">@r.Email &bull; @r.Phone</span>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

<div class="d-flex justify-content-between mt-4">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-success btn-lg" disabled="@_submitting" @onclick="HandleSubmit">
        @if (_submitting)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Submit Application
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool _submitting;
    private string? _errorMessage;

    private async Task HandleSubmit()
    {
        _submitting = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

