@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12"
              maxlength="@MaxLength"
              @bind="CoverLetter"
              @bind:event="oninput"
              @bind:after="NotifyChanged"></textarea>
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }
}

@namespace sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply
@using sv_4814acce08604935a05cd587ebe6908c.Models

<h4 class="mb-3">Review Your Application</h4>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@Personal.FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Personal.Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Personal.Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Personal.Address</dd>
        </dl>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3">
                <h6>@entry.Title at @entry.Company</h6>
                <p class="text-muted mb-1">
                    @entry.StartDate?.ToString("MMM yyyy") &ndash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                </p>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> &mdash; @r.Relationship<br />
                <span class="text-muted">@r.Email &bull; @r.Phone</span>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

<div class="d-flex justify-content-between mt-4">
    <button type="button" class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-success btn-lg" disabled="@_submitting" @onclick="HandleSubmit">
        @if (_submitting)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Submit Application
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditSection { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool _submitting;
    private string? _errorMessage;

    private async Task HandleSubmit()
    {
        _submitting = true;
        _errorMessage = null;
        StateHasChanged();

        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

