@page "/apply"
@using sv_4814acce08604935a05cd587ebe6908c.Components.Pages.Apply
@using sv_4814acce08604935a05cd587ebe6908c.Models
@using sv_4814acce08604935a05cd587ebe6908c.Services
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (_submitted)
    {
        <div class="alert alert-success text-center">
            <h4 class="alert-heading">Application Submitted!</h4>
            <p>Your application has been received. Your application ID is:</p>
            <p class="display-6 fw-bold">@_applicationId</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="_currentStep"
                       CompletedSteps="_completedSteps"
                       OnStepClicked="GoToStep" />

        <div class="mt-3">
            @switch (_currentStep)
            {
                case 0:
                    <PersonalInfoStep Model="_personalInfo"
                                      OnNext="NextStep"
                                      ValidateEmail="ApplicationService.ValidateEmailAsync" />
                    break;
                case 1:
                    <WorkHistoryStep Entries="_workEntries"
                                     OnNext="NextStep"
                                     OnBack="PreviousStep" />
                    break;
                case 2:
                    <ReferencesStep References="_references"
                                    OnNext="NextStep"
                                    OnBack="PreviousStep" />
                    break;
                case 3:
                    <CoverLetterStep CoverLetter="@_coverLetter"
                                     CoverLetterChanged="v => _coverLetter = v"
                                     OnNext="NextStep"
                                     OnBack="PreviousStep" />
                    break;
                case 4:
                    <ReviewStep Personal="_personalInfo"
                                WorkEntries="_workEntries"
                                References="_references"
                                CoverLetter="@_coverLetter"
                                OnEditSection="GoToStep"
                                OnBack="PreviousStep"
                                OnSubmit="SubmitApplication" />
                    break;
            }
        </div>
    }
</div>

@code {
    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();
    private bool _submitted;
    private int _applicationId;

    // Form state
    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private readonly List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };
    private string _coverLetter = "";

    private void NextStep()
    {
        _completedSteps.Add(_currentStep);
        if (_currentStep < 4)
        {
            _currentStep++;
        }
    }

    private void PreviousStep()
    {
        if (_currentStep > 0)
        {
            _currentStep--;
        }
    }

    private void GoToStep(int step)
    {
        if (_completedSteps.Contains(step))
        {
            _currentStep = step;
        }
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            new PersonalInfo(_personalInfo.FullName, _personalInfo.Email, _personalInfo.Phone, _personalInfo.Address),
            new WorkHistory(_workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate!.Value, e.IsCurrent ? null : e.EndDate, e.Description
            )).ToList()),
            _references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
            _coverLetter
        );

        _applicationId = await ApplicationService.SubmitApplicationAsync(application);
        _submitted = true;
    }
}

